765	void gpt2_forward(GPT2 *model, int* inputs, int* targets, size_t B, size_t T) {
766	    // targets are optional and could be NULL
767	
768	    // ensure the model was initialized or error out
769	    if (model->params_memory == NULL) {
770	        printf("Error: model was not initialized properly.\n");
771	        exit(1);
772	    }
773	
774	    // convenience parameters (size_t to help prevent int overflow)
775	    size_t V = model->config.vocab_size;
776	    size_t Vp = model->config.padded_vocab_size;
777	    size_t L = model->config.num_layers;
778	    size_t NH = model->config.num_heads;
779	    size_t C = model->config.channels;
780	
781	    // validate inputs, all indices must be in the range [0, V)
782	    for(int i = 0; i < B * T; i++) {
783	        assert(0 <= inputs[i] && inputs[i] < V);
784	        if (targets != NULL) {
785	            assert(0 <= targets[i] && targets[i] < V);
786	        }
787	    }
788	
789	    // allocate space for all the activations if needed (done here, lazily)
790	    if(model->acts_memory == NULL) {
791	        // record the current B,T as well
792	        model->batch_size = B;
793	        model->seq_len = T;
794	        // and now allocate the space
795	        fill_in_activation_sizes(model->act_sizes, model->config, B, T);
796	        size_t num_activations = 0;
797	        for (size_t i = 0; i < NUM_ACTIVATION_TENSORS; i++) {
798	            num_activations += model->act_sizes[i];
799	        }
800	        printf("num_activations: %zu\n", num_activations);
801	        model->num_activations = num_activations;
802	        model->acts_memory = malloc_and_point_activations(&model->acts, model->act_sizes);
803	        // also create memory for caching inputs and targets
804	        model->inputs = (int*)mallocCheck(B * T * sizeof(int));
805	        model->targets = (int*)mallocCheck(B * T * sizeof(int)); // might be unused if we never have targets but it's small
806	    } else {
807	        // validate B,T is consistent with how we've allocated the memory before
808	        // in principle we could get more clever here in the future, for now this is safest
809	        if (B != model->batch_size || T != model->seq_len) {
810	            printf("Model: B=%d T=%d, Desired: B=%d T=%d\n", model->batch_size, model->seq_len, (int)B, (int)T);
811	            exit(EXIT_FAILURE);
812	        }
813	    }
814	
815	    // cache the inputs/targets
816	    memcpy(model->inputs, inputs, B * T * sizeof(int));
817	    if (targets != NULL) {
818	        memcpy(model->targets, targets, B * T * sizeof(int));
819	    }
820	
821	    // forward pass
822	    ParameterTensors params = model->params; // for brevity
823	    ActivationTensors acts = model->acts;
824	    float* residual;
825	    encoder_forward(acts.encoded, inputs, params.wte, params.wpe, B, T, C); // encoding goes into residual[0]
826	    for (int l = 0; l < L; l++) {
827	
